function loadAttendanceForSelectedDate(dateVal) {
    const activeTabInput = document.querySelector('#panel-attendance #attendance-date-select');
    const val = dateVal || (activeTabInput ? activeTabInput.value : '');
    if (!val) return;

    // Sync other date input instances (e.g. in preview card)
    document.querySelectorAll('#attendance-date-select').forEach(input => {
        if (input.value !== val) input.value = val;
    });

    const thaiDate = formatToThaiDate(val);
    const history = getAttendanceHistory();
    const classVal = document.getElementById('class-select') ? document.getElementById('class-select').value : 'm3';
    const roomVal = document.getElementById('room-select') ? document.getElementById('room-select').value : '1';
    const entry = history.find(h => h.date === thaiDate && (h.class || 'm3') === classVal && (h.room || '1') === roomVal);

    const roster = (studentRosters[classVal] && studentRosters[classVal][roomVal]) ? studentRosters[classVal][roomVal] : studentRosters['m3']['1'];
    const tbody = document.getElementById('attendance-tbody-rows');
    if (!tbody) return;

    let html = '';
    roster.forEach(stu => {
        let status = entry ? entry.records[stu.id] : null;
        let actionHTML = '';
        let opacity = '1';

        if (status) {
            let badgeHTML = '';
            if (status === 'present') {
                badgeHTML = '<span class="status-badge present"><i class="fa-solid fa-check-circle"></i> มาเรียน</span>';
            } else if (status === 'late') {
                badgeHTML = '<span class="status-badge late"><i class="fa-solid fa-clock"></i> สาย</span>';
            } else if (status === 'leave') {
                badgeHTML = '<span class="status-badge leave"><i class="fa-solid fa-envelope"></i> ลา</span>';
            } else if (status === 'absent') {
                badgeHTML = '<span class="status-badge absent"><i class="fa-solid fa-xmark-circle"></i> ขาดเรียน</span>';
                opacity = '0.6';
            }
            actionHTML = badgeHTML;
        } else {
            actionHTML = `
                <div class="action-group" style="justify-content: flex-end;">
                    <button class="btn-action btn-present" onclick="markAttendance('${stu.id}', 'present')"><i class="fa-solid fa-check"></i> มา</button>
                    <button class="btn-action btn-late" onclick="markAttendance('${stu.id}', 'late')"><i class="fa-solid fa-clock"></i> สาย</button>
                    <button class="btn-action btn-leave" onclick="markAttendance('${stu.id}', 'leave')"><i class="fa-solid fa-envelope"></i> ลา</button>
                    <button class="btn-action btn-absent" onclick="markAttendance('${stu.id}', 'absent')"><i class="fa-solid fa-xmark"></i> ขาด</button>
                </div>
            `;
        }

        let loginTimeHTML = stu.loginTime;
        if (stu.loginTime === 'ยังไม่เข้าสู่ระบบ') {
            loginTimeHTML = `<span style="color: var(--danger); font-weight: 500;">ยังไม่เข้าสู่ระบบ</span>`;
        }

        let avatarStyle = '';
        if (stu.id.endsWith('2')) {
            avatarStyle = 'background: #e0f2fe; color: #0284c7;';
        } else if (stu.id.endsWith('3')) {
            avatarStyle = 'background: #ffedd5; color: #ea580c;';
        }

        html += `
            <tr id="row-${stu.id}" style="opacity: ${opacity}; transition: opacity 0.2s;">
                <td>
                    <div class="student-cell">
                        <div class="student-avatar" style="${avatarStyle}">${stu.avatar}</div>
                        <div>
                            <div style="font-weight: 500; color: var(--text-main);">${stu.name}</div>
                            <div style="font-size: 0.8rem; color: var(--text-muted);">${stu.email}</div>
                        </div>
                    </div>
                </td>
                <td style="color: var(--text-main);">${stu.code}</td>
                <td style="color: var(--text-main);">${loginTimeHTML}</td>
                <td style="text-align: right;" id="action-${stu.id}">
                    ${actionHTML}
                </td>
            </tr>
        `;
    });

    tbody.innerHTML = html;
    updateAttendanceSummary();
}

