function loadAttendanceForSelectedDate(dateVal) {
    const activeTabInput = document.querySelector('#panel-attendance #attendance-date-select');
    const val = dateVal || (activeTabInput ? activeTabInput.value : '');
    if (!val) return;

    // Sync other date input instances (e.g. in preview card)
    document.querySelectorAll('#attendance-date-select').forEach(input => {
        if (input.value !== val) input.value = val;
    });

    const thaiDate = formatToThaiDate(val);
    const history = getAttendanceHistory();
    const classVal = document.getElementById('class-select') ? document.getElementById('class-select').value : 'm3';
    const roomVal = document.getElementById('room-select') ? document.getElementById('room-select').value : '1';
    const periodVal = document.getElementById('period-select') ? document.getElementById('period-select').value : '1';
    const entry = history.find(h => h.date === thaiDate && (h.class || 'm3') === classVal && (h.room || '1') === roomVal && (h.period || '1') === periodVal);

    const studentIds = ['stu-1', 'stu-2', 'stu-3'];
    studentIds.forEach(id => {
        const actionCells = document.querySelectorAll('[id="action-' + id + '"]');
        const rows = document.querySelectorAll('[id="row-' + id + '"]');

        if (entry && entry.records[id]) {
            const status = entry.records[id];
            let badgeHTML = '';
            if (status === 'present') {
                badgeHTML = '<span class="status-badge present"><i class="fa-solid fa-check-circle"></i> มาเรียน</span>';
            } else if (status === 'late') {
                badgeHTML = '<span class="status-badge late"><i class="fa-solid fa-clock"></i> สาย</span>';
            } else if (status === 'leave') {
                badgeHTML = '<span class="status-badge leave"><i class="fa-solid fa-envelope"></i> ลา</span>';
            } else if (status === 'absent') {
                badgeHTML = '<span class="status-badge absent"><i class="fa-solid fa-xmark-circle"></i> ขาดเรียน</span>';
            }

            actionCells.forEach(cell => {
                cell.innerHTML = badgeHTML;
                cell.style.opacity = '1';
            });
            rows.forEach(row => {
                row.style.opacity = status === 'absent' ? '0.6' : status === 'leave' ? '0.85' : '1';
            });
        } else {
            const buttonsHTML = `
                <div class="action-group" style="justify-content: flex-end;">
                    <button class="btn-action btn-present" onclick="markAttendance('${id}', 'present')"><i class="fa-solid fa-check"></i> มา</button>
                    <button class="btn-action btn-late" onclick="markAttendance('${id}', 'late')"><i class="fa-solid fa-clock"></i> สาย</button>
                    <button class="btn-action btn-leave" onclick="markAttendance('${id}', 'leave')"><i class="fa-solid fa-envelope"></i> ลา</button>
                    <button class="btn-action btn-absent" onclick="markAttendance('${id}', 'absent')"><i class="fa-solid fa-xmark"></i> ขาด</button>
                </div>
            `;
            actionCells.forEach(cell => {
                cell.innerHTML = buttonsHTML;
                cell.style.opacity = '1';
            });
            rows.forEach(row => {
                row.style.opacity = '1';
            });
        }
    });
    updateAttendanceSummary();
}
